import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        dir_abs = os.path.abspath(dir_path)
        full_path = os.path.join(dir_abs, filename)
        if not full_path.startswith(dir_abs):
            return ""
        if not os.path.isfile(full_path):
            return ""
        with open(full_path, 'r') as f:
            return f.read()
    except:
        return ""

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    if not subdomain_prefix:
        return f"https://{domain}"
    return f"https://{subdomain_prefix}.{domain}"

def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not user_id:
        return None
    return f"{api_url}/{user_id}"

import re
from typing import Tuple

def check_email(email: str) -> Tuple[bool, str]:
    pattern = r'^[a-zA-Z0-9._%+-]+@[a-zA-Z0-9-]+(\.[a-zA-Z0-9-]+)*\.[a-zA-Z]{2,}$'
    return (bool(re.fullmatch(pattern, email)), pattern)

import subprocess

def get_ls_result(dir_path: str) -> str:
    try:
        result = subprocess.run(['ls', '-l', dir_path], capture_output=True, text=True, check=True)
        return result.stdout
    except subprocess.CalledProcessError:
        return ""
    except Exception:
        return ""
